#include <bits/stdc++.h>
using namespace std;
int t,n,a[10004];
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]);
        for(int i=1;i<=n;i++)
            if(i!=2)
                a[2]/=__gcd(a[2],a[i]);
        if(a[2]==1)
            printf("Yes\n");
        else
            printf("No\n");
    }
    return 0;
}
